use serde::{Deserialize, Serialize};
use std::io::{self, Read};

pub const PI: f64 = 3.1415926535;

#[derive(Debug, Deserialize, Serialize)]
pub struct Parameters {
    #[serde(rename = "LENGTH1")]
    pub length1: f64,
    #[serde(rename = "RADIUS1")]
    pub radius1: f64,
    #[serde(rename = "EPSILON")]
    pub epsilon: f64,
    #[serde(rename = "AREA1")]
    pub area1: f64,
    #[serde(rename = "Q_PTS")]
    pub q_pts: i32,
    #[serde(rename = "QUADS")]
    pub quads: i32,
    #[serde(rename = "DIST")]
    pub dist: f64,
    #[serde(rename = "N_PTS")]
    pub n_pts: i32,
    #[serde(rename = "K_PTS")]
    pub k_pts: i32,
    #[serde(rename = "A_PTS")]
    pub a_pts: i32,
    #[serde(rename = "B_PTS")]
    pub b_pts: i32,
    #[serde(rename = "C_PTS")]
    pub c_pts: i32,
    #[serde(rename = "D_PTS")]
    pub d_pts: i32,
    #[serde(rename = "E_PTS")]
    pub e_pts: i32,
    #[serde(rename = "F_PTS")]
    pub f_pts: i32,
    #[serde(rename = "G_PTS")]
    pub g_pts: i32,
    #[serde(rename = "LENGTH2")]
    pub length2: f64,
    #[serde(rename = "RADIUS2")]
    pub radius2: f64,
    #[serde(rename = "AREA2")]
    pub area2: f64,
}

#[derive(Debug, Deserialize, Serialize)]
pub struct Input {
    pub numpoints: i32,
    pub x: Vec<f64>,
    pub y: Vec<f64>,
    pub parameters: Parameters,
    pub lcm: Vec<Vec<String>>,
    pub pum_diag: Vec<bool>,
}

#[derive(Debug, Serialize)]
pub struct Output {
    pub cmv: Vec<bool>,
    pub pum: Vec<Vec<bool>>,
    pub fuv: Vec<bool>,
    pub launch: bool,
}

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x1 - x2).powi(2) + (y1 - y2).powi(2)).sqrt()
}

fn get_quadrant(x: f64, y: f64) -> i32 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

fn is_not_contained_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    let d12 = dist(x1, y1, x2, y2);
    let d23 = dist(x2, y2, x3, y3);
    let d31 = dist(x3, y3, x1, y1);

    let max_d = d12.max(d23).max(d31);
    if realcompare(max_d, 2.0 * radius) == "GT" {
        return true;
    }

    // Check if acute. Sort sides such that c is max.
    let mut sides = [d12, d23, d31];
    sides.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let (a, b, c) = (sides[0], sides[1], sides[2]);

    // acute if a^2 + b^2 > c^2
    if realcompare(a.powi(2) + b.powi(2), c.powi(2)) == "GT" {
        let area = triangle_area(x1, y1, x2, y2, x3, y3);
        if realcompare(area, 0.0) == "EQ" {
            // Collinear - already handled by max_d > 2*radius check above
            // but for safety:
            return realcompare(c / 2.0, radius) == "GT";
        }
        let circumradius = (a * b * c) / (4.0 * area);
        return realcompare(circumradius, radius) == "GT";
    }

    // Obtuse or right: smallest circle has radius c/2
    realcompare(c / 2.0, radius) == "GT"
}

fn is_contained_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    !is_not_contained_in_circle(x1, y1, x2, y2, x3, y3, radius)
}

pub fn decide(input: &Input) -> Output {
    let n = input.numpoints as usize;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    let mut cmv = vec![false; 15];

    // LIC 1
    for i in 0..n - 1 {
        if realcompare(dist(x[i], y[i], x[i + 1], y[i + 1]), p.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..n - 2 {
        if is_not_contained_in_circle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], p.radius1) {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..n - 2 {
        let (x1, y1) = (x[i], y[i]);
        let (x2, y2) = (x[i + 1], y[i + 1]);
        let (x3, y3) = (x[i + 2], y[i + 2]);

        if (realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ") ||
           (realcompare(x3, x2) == "EQ" && realcompare(y3, y2) == "EQ") {
            continue;
        }

        let v1 = (x1 - x2, y1 - y2);
        let v2 = (x3 - x2, y3 - y2);
        let dot = v1.0 * v2.0 + v1.1 * v2.1;
        let mag1 = (v1.0.powi(2) + v1.1.powi(2)).sqrt();
        let mag2 = (v2.0.powi(2) + v2.1.powi(2)).sqrt();
        let cos_theta = dot / (mag1 * mag2);
        // Clamp cos_theta due to precision
        let cos_theta = cos_theta.max(-1.0).min(1.0);
        let theta = cos_theta.acos();

        if realcompare(theta, PI - p.epsilon) == "LT" || realcompare(theta, PI + p.epsilon) == "GT" {
            cmv[2] = true;
            break;
        }
    }

    // LIC 4
    for i in 0..n - 2 {
        if realcompare(triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]), p.area1) == "GT" {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    let q_pts = p.q_pts as usize;
    for i in 0..=n - q_pts {
        let mut quads = [false; 4];
        for j in 0..q_pts {
            quads[(get_quadrant(x[i + j], y[i + j]) - 1) as usize] = true;
        }
        let count = quads.iter().filter(|&&b| b).count();
        if count > p.quads as usize {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6
    for i in 0..n - 1 {
        if realcompare(x[i + 1] - x[i], 0.0) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 {
        let n_pts = p.n_pts as usize;
        for i in 0..=n - n_pts {
            let (x_f, y_f) = (x[i], y[i]);
            let (x_l, y_l) = (x[i + n_pts - 1], y[i + n_pts - 1]);
            let line_len = dist(x_f, y_f, x_l, y_l);

            for j in 1..n_pts - 1 {
                let (x0, y0) = (x[i + j], y[i + j]);
                let d = if realcompare(line_len, 0.0) == "EQ" {
                    dist(x0, y0, x_f, y_f)
                } else {
                    ((y_l - y_f) * x0 - (x_l - x_f) * y0 + x_l * y_f - y_l * x_f).abs() / line_len
                };
                if realcompare(d, p.dist) == "GT" {
                    cmv[6] = true;
                    break;
                }
            }
            if cmv[6] { break; }
        }
    }

    // LIC 8
    if n >= 3 {
        let k_pts = p.k_pts as usize;
        for i in 0..n - k_pts - 1 {
            if realcompare(dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1]), p.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        let a_pts = p.a_pts as usize;
        let b_pts = p.b_pts as usize;
        for i in 0..n - a_pts - b_pts - 2 {
            if is_not_contained_in_circle(x[i], y[i], x[i + a_pts + 1], y[i + a_pts + 1], x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2], p.radius1) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        let c_pts = p.c_pts as usize;
        let d_pts = p.d_pts as usize;
        for i in 0..n - c_pts - d_pts - 2 {
            let (x1, y1) = (x[i], y[i]);
            let (x2, y2) = (x[i + c_pts + 1], y[i + c_pts + 1]);
            let (x3, y3) = (x[i + c_pts + d_pts + 2], y[i + c_pts + d_pts + 2]);

            if (realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ") ||
               (realcompare(x3, x2) == "EQ" && realcompare(y3, y2) == "EQ") {
                continue;
            }

            let v1 = (x1 - x2, y1 - y2);
            let v2 = (x3 - x2, y3 - y2);
            let dot = v1.0 * v2.0 + v1.1 * v2.1;
            let mag1 = (v1.0.powi(2) + v1.1.powi(2)).sqrt();
            let mag2 = (v2.0.powi(2) + v2.1.powi(2)).sqrt();
            let cos_theta = dot / (mag1 * mag2);
            let cos_theta = cos_theta.max(-1.0).min(1.0);
            let theta = cos_theta.acos();

            if realcompare(theta, PI - p.epsilon) == "LT" || realcompare(theta, PI + p.epsilon) == "GT" {
                cmv[9] = true;
                break;
            }
        }
    }

    // LIC 11
    if n >= 5 {
        let e_pts = p.e_pts as usize;
        let f_pts = p.f_pts as usize;
        for i in 0..n - e_pts - f_pts - 2 {
            if realcompare(triangle_area(x[i], y[i], x[i + e_pts + 1], y[i + e_pts + 1], x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2]), p.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 {
        let g_pts = p.g_pts as usize;
        for i in 0..n - g_pts - 1 {
            if realcompare(x[i + g_pts + 1] - x[i], 0.0) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 {
        let mut part1 = false;
        let mut part2 = false;
        let k_pts = p.k_pts as usize;
        for i in 0..n - k_pts - 1 {
            let d = dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1]);
            if realcompare(d, p.length1) == "GT" {
                part1 = true;
            }
            if realcompare(d, p.length2) == "LT" {
                part2 = true;
            }
            if part1 && part2 { break; }
        }
        cmv[12] = part1 && part2;
    }

    // LIC 14
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        let a_pts = p.a_pts as usize;
        let b_pts = p.b_pts as usize;
        for i in 0..n - a_pts - b_pts - 2 {
            if is_not_contained_in_circle(x[i], y[i], x[i + a_pts + 1], y[i + a_pts + 1], x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2], p.radius1) {
                part1 = true;
            }
            if is_contained_in_circle(x[i], y[i], x[i + a_pts + 1], y[i + a_pts + 1], x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2], p.radius2) {
                part2 = true;
            }
            if part1 && part2 { break; }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        let e_pts = p.e_pts as usize;
        let f_pts = p.f_pts as usize;
        for i in 0..n - e_pts - f_pts - 2 {
            let area = triangle_area(x[i], y[i], x[i + e_pts + 1], y[i + e_pts + 1], x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2]);
            if realcompare(area, p.area1) == "GT" {
                part1 = true;
            }
            if realcompare(area, p.area2) == "LT" {
                part2 = true;
            }
            if part1 && part2 { break; }
        }
        cmv[14] = part1 && part2;
    }

    // PUM
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
                continue;
            }
            let conn = &input.lcm[i][j];
            if conn == "NOTUSED" {
                pum[i][j] = true;
            } else if conn == "ANDD" {
                pum[i][j] = cmv[i] && cmv[j];
            } else if conn == "ORR" {
                pum[i][j] = cmv[i] || cmv[j];
            }
        }
    }

    // FUV
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !input.pum_diag[i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if i != j && !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    // LAUNCH
    let launch = fuv.iter().all(|&b| b);

    Output {
        cmv,
        pum,
        fuv,
        launch,
    }
}

fn main() {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).unwrap();
    let input: Input = serde_json::from_str(&buffer).unwrap();
    let output = decide(&input);
    println!("{}", serde_json::to_string(&output).unwrap());
}
